const body = $input.first().json.body;
if (!body?.entry?.[0]?.changes?.[0]?.value?.messages) return [];

const value   = body.entry[0].changes[0].value;
const msg     = value.messages[0];
const phone   = msg.from;
const phoneId = value.metadata.phone_number_id;
const profile = value.contacts?.[0]?.profile?.name || 'Patient';
const msgType = msg.type;
const msgId   = msg.id;
const timestamp = msg.timestamp;

const data = $getWorkflowStaticData('global');
if (!data.processed) data.processed = {};
const oneHourAgo = Date.now() - 3600000;
Object.keys(data.processed).filter(k => data.processed[k] < oneHourAgo).forEach(k => delete data.processed[k]);
if (data.processed[msgId]) return [];
data.processed[msgId] = Date.now();

if (!data.rateLimit) data.rateLimit = {};
const now = Date.now();
if (now - (data.rateLimit[phone] || 0) < 1500) return [];
data.rateLimit[phone] = now;

let userText = '';
let buttonId = null;
let rawInteractiveType = null;

switch (msgType) {
  case 'text':
    userText = msg.text.body.trim();
    break;
  case 'interactive': {
    rawInteractiveType = msg.interactive.type;
    if (rawInteractiveType === 'button_reply') {
      buttonId = msg.interactive.button_reply.id;
      userText = msg.interactive.button_reply.title;
    } else if (rawInteractiveType === 'list_reply') {
      buttonId = msg.interactive.list_reply.id;
      userText = msg.interactive.list_reply.title;
    }
    break;
  }
  case 'location': {
    const loc = msg.location;
    userText = `LOCATION: lat=${loc.latitude}, lng=${loc.longitude}`;
    if (loc.name) userText += `, name=${loc.name}`;
    break;
  }
  default:
    userText = `[${msgType} message received]`;
}

if (!userText) return [];
return [{ json: { phone, phoneId, profile, msgType, rawInteractiveType, userText, buttonId, msgId, timestamp } }];

const ing = $('Ingest Message').first().json;
const { phone, phoneId, profile, userText, buttonId, msgType, rawInteractiveType } = ing;

const sessionItems = $('Load Session').all().map(i => i.json);
const session = (sessionItems.length > 0 && sessionItems[0].phone)
  ? sessionItems[0]
  : { booking_draft: {}, last_intent: 'none', message_count: 0 };

const convItems = $('Load Convo').all().map(i => i.json);
const history = convItems.filter(h => h && h.role && h.content).reverse().slice(-12);
const histText = history.length
  ? history.map(h => `${h.role === 'assistant' ? 'LyncDoc' : 'Patient'}: ${h.content}`).join('\n')
  : '(new conversation)';

let draftObj = {};
try {
  const bd = session.booking_draft;
  draftObj = typeof bd === 'string' ? JSON.parse(bd) : (bd && typeof bd === 'object' ? bd : {});
} catch(_) {}
const draft = Object.keys(draftObj).length ? JSON.stringify(draftObj, null, 2) : '{}';

const now = new Date();
const today = now.toISOString().split('T')[0];
const time = now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: true, timeZone: 'Asia/Kolkata' });
const dayName = now.toLocaleDateString('en-IN', { weekday: 'long', timeZone: 'Asia/Kolkata' });

// Resolve today/tomorrow to actual dates in IST
const nowIST = new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Kolkata' }));
function isoDate(d) { return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0'); }
const todayDate = isoDate(nowIST);
const tomorrowDate = (() => { const t = new Date(nowIST); t.setDate(t.getDate()+1); return isoDate(t); })();

let messageContext = '';
if (buttonId) {
  if (buttonId === 'btn_confirm_booking') {
    messageContext = 'ACTION: PATIENT CONFIRMED BOOKING. Call create_booking_request tool NOW using these exact values from the draft above: patient_name, patient_age, patient_gender, specialty_id, symptoms, pincode, preferred_date, preferred_time_slot.';
  } else if (buttonId === 'btn_cancel_booking') {
    messageContext = 'ACTION: Patient cancelled booking flow. Do NOT create booking. Respond politely and clear draft.';
  } else if (buttonId === 'btn_today') {
    messageContext = `ACTION: Patient chose Today. Save to draft: preferred_date = ${todayDate}`;
  } else if (buttonId === 'btn_tomorrow') {
    messageContext = `ACTION: Patient chose Tomorrow. Save to draft: preferred_date = ${tomorrowDate}`;
  } else if (buttonId === 'btn_pick_date') {
    messageContext = 'ACTION: Patient wants to pick a specific date. Ask them to type a date (e.g. "15 April" or "next Monday"). Today is ' + todayDate + '.';
  } else if (buttonId === 'btn_morning') {
    messageContext = 'ACTION: Patient chose Morning. Save to draft: preferred_time_slot = Morning';
  } else if (buttonId === 'btn_afternoon') {
    messageContext = 'ACTION: Patient chose Afternoon. Save to draft: preferred_time_slot = Afternoon';
  } else if (buttonId === 'btn_evening') {
    messageContext = 'ACTION: Patient chose Evening. Save to draft: preferred_time_slot = Evening';
  } else if (buttonId === 'btn_male') {
    messageContext = 'ACTION: Patient chose Male. Save to draft: patient_gender = Male';
  } else if (buttonId === 'btn_female') {
    messageContext = 'ACTION: Patient chose Female. Save to draft: patient_gender = Female';
  } else if (buttonId === 'btn_other_gender') {
    messageContext = 'ACTION: Patient chose Other gender. Save to draft: patient_gender = Other';
  } else if (buttonId === 'btn_book') {
    messageContext = 'ACTION: Patient wants to book a doctor. Start the booking flow from step 1 (symptoms).';
  } else if (buttonId === 'btn_bookings') {
    messageContext = 'ACTION: Patient wants to see their bookings. Call get_bookings tool.';
  } else if (buttonId === 'btn_help') {
    messageContext = 'ACTION: Patient wants to talk to a support agent. Set intent=support.';
  } else if (buttonId.startsWith('cancel_')) {
    messageContext = `ACTION: Cancel booking_ref=${buttonId.replace('cancel_', '')}`;
  } else if (buttonId.startsWith('view_')) {
    messageContext = `ACTION: Show details for booking_ref=${buttonId.replace('view_', '')}`;
  } else {
    messageContext = `BUTTON: ${buttonId}`;
  }
}

const lastAIMsg = history.filter(h => h.role === 'assistant').slice(-1)[0];
let lastQuestion = '';
if (lastAIMsg && !buttonId) {
  const m = lastAIMsg.content.toLowerCase();
  if (m.includes('full name') || m.includes("patient's name")) lastQuestion = 'patient_name';
  else if (m.includes('how old') || m.includes('age')) lastQuestion = 'patient_age';
  else if (m.includes('gender')) lastQuestion = 'patient_gender';
  else if (m.includes('symptom') || m.includes('reason') || m.includes('what brings') || m.includes('how can i help')) lastQuestion = 'symptoms';
  else if (m.includes('pincode') || m.includes('pin code')) lastQuestion = 'pincode';
  else if (m.includes('when would') || m.includes('preferred date') || m.includes('like the visit')) lastQuestion = 'preferred_date';
  else if (m.includes('time works') || (m.includes('morning') && m.includes('afternoon'))) lastQuestion = 'preferred_time';
}

const missingFields = [];
if (!draftObj.specialty_id) missingFields.push('specialty_id');
if (!draftObj.pincode) missingFields.push('pincode');
if (!draftObj.preferred_date) missingFields.push('preferred_date');
if (!draftObj.preferred_time_slot) missingFields.push('preferred_time_slot');
if (!draftObj.patient_name) missingFields.push('patient_name');
if (!draftObj.patient_age) missingFields.push('patient_age');
if (!draftObj.patient_gender) missingFields.push('patient_gender');

let answerContext = '';
if (lastQuestion && msgType === 'text' && !buttonId) {
  answerContext = `ANSWER: Patient answered "${userText}" for ${lastQuestion}. Save to draft_update and proceed.`;
}

const prompt = [
  '=== PATIENT ===' ,
  `PHONE: ${phone} | NAME: ${profile}`,
  `DATE: ${today} (${dayName}) | TIME: ${time} IST`,
  `LAST_INTENT: ${session.last_intent || 'none'} | MSG_COUNT: ${session.message_count || 0}`,
  '',
  '=== BOOKING DRAFT ===',
  draft,
  '',
  missingFields.length ? `NEXT_MISSING: ${missingFields[0]}` : 'ALL FIELDS COLLECTED',
  '',
  '=== HISTORY ===',
  histText,
  '',
  '=== NOW ===',
  `Patient: "${userText}"`,
  messageContext,
  answerContext
].filter(Boolean).join('\n');

return [{ json: { phone, phoneId, profile, userText, buttonId, msgType, draftObj, prompt } }];

