const raw = $input.first().json.output || $input.first().json.text || '';
const phone    = $('Context Builder').first().json.phone;
const phoneId  = $('Context Builder').first().json.phoneId;
const profile  = $('Context Builder').first().json.profile;
const userText = $('Context Builder').first().json.userText;
const msgType  = $('Context Builder').first().json.msgType;
const draftObj = $('Context Builder').first().json.draftObj || {};

let ai = null;

try {
  let clean = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  const s = clean.indexOf('{');
  const e = clean.lastIndexOf('}');
  if (s !== -1 && e !== -1 && e > s) ai = JSON.parse(clean.slice(s, e + 1));
} catch (_) {}

if (!ai) {
  try {
    let clean = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
    const s = clean.indexOf('{');
    if (s !== -1) {
      let partial = clean.slice(s);
      let depth = 0, lastValid = -1;
      for (let i = 0; i < partial.length; i++) {
        if (partial[i] === '{') depth++;
        if (partial[i] === '}') { depth--; if (depth === 0) lastValid = i; }
      }
      if (lastValid > 0) ai = JSON.parse(partial.slice(0, lastValid + 1));
      else {
        const m = partial.match(/"message"\s*:\s*"((?:[^"\\]|\\.)*)"/);
        if (m) ai = { message: m[1].replace(/\\n/g, '\n'), component: 'text', intent: 'unknown', draft_update: null };
      }
    }
  } catch (_2) {}
}

if (ai && (!ai.message || typeof ai.message !== 'string' || !ai.message.trim())) ai = null;

if (ai) {
  ai.message = String(ai.message).slice(0, 1024);
  if (!['text','buttons','list'].includes(ai.component)) ai.component = 'text';
  if (ai.component === 'buttons') {
    if (!Array.isArray(ai.buttons) || !ai.buttons.length) ai.component = 'text';
    else ai.buttons = ai.buttons.slice(0, 3).map(b => ({ id: String(b.id||'btn').slice(0,256), title: String(b.title||'').slice(0,20) }));
  }
  if (ai.component === 'list') {
    if (!Array.isArray(ai.list_sections) || !ai.list_sections.length) ai.component = 'text';
    else {
      ai.list_sections = ai.list_sections.map(sec => ({
        title: String(sec.title||'Options').slice(0,24),
        rows: (sec.rows||[]).filter(r=>r?.id&&r?.title).slice(0,10).map(r=>({
          id:String(r.id).slice(0,200), title:String(r.title).slice(0,24),
          ...(r.description?{description:String(r.description).slice(0,72)}:{})
        }))
      })).filter(s=>s.rows.length);
      if (!ai.list_sections.length) ai.component = 'text';
    }
  }
  const vi = ['book','cancel','my_bookings','greeting','emergency','support','unknown','booking_created','cancel_confirmed'];
  if (!vi.includes(ai.intent)) ai.intent = 'unknown';
  if (ai.draft_update !== null && typeof ai.draft_update !== 'object') ai.draft_update = null;
}

if (!ai) {
  ai = { message: "Something went wrong. Please send *hi* to start again.", component: 'text', intent: 'unknown', draft_update: null };
}

return [{ json: { phone, phoneId, profile, userText, msgType, ai } }];

const phone   = $('Ingest Message').first().json.phone;
const profile = $('Ingest Message').first().json.profile;
const ai      = $('Parse Response').first().json.ai;

const sessionItems = $('Load Session').all().map(i => i.json);
const existing = (sessionItems.length > 0 && sessionItems[0].phone)
  ? sessionItems[0] : { booking_draft: {}, message_count: 0 };

let existingDraft = {};
try {
  const bd = existing.booking_draft;
  existingDraft = typeof bd === 'string' ? JSON.parse(bd) : (bd && typeof bd === 'object' ? bd : {});
} catch(_) {}

let newDraft = { ...existingDraft };
if (ai.draft_update && typeof ai.draft_update === 'object' && !Array.isArray(ai.draft_update)) {
  newDraft = { ...existingDraft, ...ai.draft_update };
  Object.keys(newDraft).forEach(k => { if (newDraft[k] === null || newDraft[k] === undefined) delete newDraft[k]; });
}

const clearIntents = ['booking_created', 'cancel_confirmed', 'greeting'];
if (clearIntents.includes(ai.intent)) newDraft = {};

const aiMsg = ai.message || '';
if (aiMsg.includes('LYN') && (aiMsg.toLowerCase().includes('booking') && (aiMsg.toLowerCase().includes('placed') || aiMsg.toLowerCase().includes('confirmed')))) newDraft = {};

const userText = $('Ingest Message').first().json.userText || '';
if (['hi','hello','hey','start','menu','restart'].includes(userText.toLowerCase().trim())) newDraft = {};

const buttonId = $('Ingest Message').first().json.buttonId || '';
if (buttonId === 'btn_cancel_booking') newDraft = {};

const sessionUpsert = {
  phone,
  profile_name: profile,
  booking_draft: newDraft,
  last_intent: ai.intent || 'unknown',
  last_active: new Date().toISOString(),
  message_count: (existing.message_count || 0) + 1
};

return [{ json: { phone, sessionUpsert, ai } }];

const { phone, phoneId, ai } = $('Parse Response').first().json;

if (!ai?.message) {
  return [{ json: { phoneId, payload: {
    messaging_product: 'whatsapp', to: phone, type: 'text',
    text: { body: 'Something went wrong. Send *hi* to restart.' }
  }}}];
}

const msg = String(ai.message).slice(0, 1024);
const comp = ai.component || 'text';
let payload;

if (comp === 'buttons' && Array.isArray(ai.buttons) && ai.buttons.length > 0) {
  const buttons = ai.buttons.slice(0,3).filter(b=>b?.id&&b?.title).map(b=>({
    type:'reply', reply:{id:String(b.id).slice(0,256), title:String(b.title).slice(0,20)}
  }));
  payload = buttons.length ? {
    messaging_product:'whatsapp', recipient_type:'individual', to:phone,
    type:'interactive', interactive:{type:'button', body:{text:msg}, action:{buttons}}
  } : {messaging_product:'whatsapp', to:phone, type:'text', text:{body:msg}};
} else if (comp === 'list' && Array.isArray(ai.list_sections) && ai.list_sections.length > 0) {
  const sections = ai.list_sections.map(sec=>({
    title:String(sec.title||'Options').slice(0,24),
    rows:(sec.rows||[]).filter(r=>r?.id&&r?.title).slice(0,10).map(r=>({
      id:String(r.id).slice(0,200), title:String(r.title).slice(0,24),
      ...(r.description?{description:String(r.description).slice(0,72)}:{})
    }))
  })).filter(s=>s.rows.length);
  payload = sections.length ? {
    messaging_product:'whatsapp', recipient_type:'individual', to:phone,
    type:'interactive', interactive:{
      type:'list', body:{text:msg},
      action:{button:String(ai.list_button_label||'Select').slice(0,20), sections}
    }
  } : {messaging_product:'whatsapp', to:phone, type:'text', text:{body:msg}};
} else {
  payload = {messaging_product:'whatsapp', to:phone, type:'text', text:{body:msg}};
}

return [{ json: { phoneId, payload } }];
